def initialize_model():
    """Initialize the GENRE model if available."""
    # Match the model path used in server.py
    MODEL_NAME = "fairseq_entity_disambiguation_aidayago"
    MODEL_DIR = "/home/lars/GENRE/models"
    MODEL_PATH = os.path.join(MODEL_DIR, MODEL_NAME)
    
    if os.path.isdir(MODEL_PATH):
        print(f"Initializing model from {MODEL_PATH}")
        set_model(MODEL_PATH)
        print("✓ Model initialized successfully")
        return True
    else:
        print(f"⚠ Model not found at {MODEL_PATH}")
        print("  Tests will run without model (validation only)")
        return False

