def test_dict_conversion():
    """Test dict to text conversion functions."""
    print("Test 2: Dict conversion helpers")
    
    # Test data2text
    test_dict = {"name": "Apple Inc.", "founded": "1976", "industry": "Technology"}
    text = data2text(test_dict, ["name", "founded", "industry"])
    print(f"  data2text result: {text}")
    assert text == "name: Apple Inc., founded: 1976, industry: Technology."
    print("  ✓ data2text works correctly")
    
    # Test with NULL value filtering
    test_dict_null = {"name": "Test", "founded": "", "industry": "Tech"}
    text_null = data2text(test_dict_null, ["name", "founded", "industry"])
    print(f"  data2text with null: {text_null}")
    assert "name: Test" in text_null
    assert "founded:" not in text_null  # Empty value should be filtered
    print("  ✓ NULL value filtering works correctly")
    
    # Test get_shared_keys
    candidates = [
        {"name": "Apple", "founded": "1976", "industry": "Tech"},
        {"name": "Microsoft", "founded": "1975", "industry": "Tech"}
    ]
    data = [
        {"name": "Apple", "founded": "1976", "industry": "Tech"},
    ]
    shared = get_shared_keys(data, candidates)
    print(f"  Shared keys: {shared}")
    assert "name" in shared
    assert "founded" in shared
    assert "industry" in shared
    print("  ✓ get_shared_keys works correctly")
    
    print()

def test_empty_inputs():
    """Test handling of empty inputs."""
    print("Test 3: Empty inputs")
    
    try:
        result = link_entities([], [])
        assert result == [], "Empty lists should return empty result"
        print("  ✓ Empty lists handled correctly")
    except Exception as e:
        print(f"  ✗ Error: {e}")
    
    try:
        result = link_entities([{"name": "test"}], [])
        assert result == [], "Empty data_entries should return empty result"
        print("  ✓ Empty data_entries handled correctly")
    except Exception as e:
        print(f"  ✗ Error: {e}")
    
    print()

def test_no_shared_keys():
    """Test handling when no shared keys exist."""
    print("Test 4: No shared keys scenario")
    
    # No overlapping keys
    candidates = [
        {"name": "Apple", "founded": "1976"}
    ]
    data = [
        {"title": "Some Entry", "description": "Test"}
    ]
    
    result = link_entities(candidates, data)
    print(f"  Result: {result}")
    assert result == [-1], "Should return -1 when no shared keys"
    print("  ✓ Correctly handles no shared keys")
    
    print()

def test_api_compatibility():
    """Test that the API is compatible with existing server."""
    print("Test 5: API compatibility")
    
    # Check that the function signature matches what the server expects
    import inspect
    sig = inspect.signature(link_entities)
    params = list(sig.parameters.keys())
    
    expected_params = [
        'table_rows',
        'data_entries'
    ]
    
    if params == expected_params:
        print("  ✓ Function signature matches server expectations")
    else:
        print(f"  ✗ Parameter mismatch. Expected: {expected_params}, Got: {params}")
    
    # Check return type annotation
    return_annotation = sig.return_annotation
    print(f"  Return type annotation: {return_annotation}")
    
    # Check parameter types
    candidate_type = sig.parameters['table_rows'].annotation
    data_type = sig.parameters['data_entries'].annotation
